def resolve_credentials(args: argparse.Namespace) -> argparse.Namespace:
    """Resolve credentials from environment variables if not provided via CLI."""
    if not args.ssl_password:
        args.ssl_password = os.environ.get("KAFKA_SSL_PASSWORD")

    if not args.sasl_username:
        args.sasl_username = os.environ.get("KAFKA_SASL_USERNAME")

    if not args.sasl_password:
        args.sasl_password = os.environ.get("KAFKA_SASL_PASSWORD")

    return args


def validate_bootstrap_servers(servers: str) -> bool:
    """Validate bootstrap servers format."""
    pattern = re.compile(
        r"^[a-zA-Z0-9._-]+:\d{1,5}(,[a-zA-Z0-9._-]+:\d{1,5})*$"
    )
    if not pattern.match(servers):
        logger.error(
            f"Invalid bootstrap servers format: '{servers}'. "
            "Expected format: host1:port1,host2:port2"
        )
        return False

    # Validate port ranges
    for server in servers.split(","):
        _, port_str = server.rsplit(":", 1)
        port = int(port_str)
        if not 1 <= port <= 65535:
            logger.error(f"Invalid port number: {port}")
            return False

    return True


def main() -> int:
    """Main entry point for the Kafka administration tool."""
    parser = build_parser()
    args = parser.parse_args()

    if not args.command:
        parser.print_help()
        return 1

    if args.verbose:
        logging.getLogger().setLevel(logging.DEBUG)

    # Validate bootstrap servers
    if not validate_bootstrap_servers(args.bootstrap_servers):
        return 1

    # Resolve credentials from environment variables
    args = resolve_credentials(args)

    # Command dispatch table
    command_handlers = {
        "create": create_topic,
        "delete": delete_topic,
        "list": list_topics,
        "describe": describe_topic,
        "add-partitions": add_partitions,
        "configure": configure_topic,
    }

    handler = command_handlers.get(args.command)
    if not handler:
        logger.error(f"Unknown command: {args.command}")
        parser.print_help()
        return 1

    # Create admin client
    admin_client = create_admin_client(args)
    if admin_client is None:
        return 1

    try:
        success = handler(admin_client, args)
        return 0 if success else 1
    except KeyboardInterrupt:
        logger.info("Operation cancelled by user")
        return 130
    except Exception as e:
        logger.error(f"Unexpected error: {e}")
        if args.verbose:
            import traceback
            traceback.print_exc()
        return 1
    finally:
        try:
            admin_client.close()
            logger.debug("Admin client connection closed")
        except Exception:
            pass


if __name__ == "__main__":
    sys.exit(main())